import { useState } from 'react';
import Button from 'react-bootstrap/Button';
import Modal from 'react-bootstrap/Modal';
import { PlusLg ,FileEarmarkPlus } from "react-bootstrap-icons";
import RadioButton from './RadioButton';


const ContactAdd = () => {
  const [show, setShow] = useState(false);

  const handleClose = () => setShow(false);
  const handleShow = () => setShow(true);
  return (
   <>
     <Button variant="ContactAdd" onClick={handleShow}>
     <PlusLg color="#9E77ED" size={16} />
      </Button>

      <Modal show={show} onHide={handleClose} animation={false}>
        <Modal.Header closeButton>
        <div className='modelHeader d-flex justify-content-between align-items-start'>
        <span>
        <div className='iconOutStyle'>
        <div className='iconinStyle'>
        <div className='iconinnerStyle'>
        <FileEarmarkPlus color="#17B26A" size={16} />
        </div>
        </div>
        </div>
        Add Note</span>
        </div>
        </Modal.Header>
        <Modal.Body><RadioButton /></Modal.Body>
      </Modal>
   </>
  )
}
export default ContactAdd