import * as React from "react";
import { QuestionCircle, Search, PlusLg } from 'react-bootstrap-icons';


const ProfileInfo = ({ username, userType ,aliasName }) => {
  return (
    <>
      <div className="avatar-wrap flexEndbox colMinWidth">
    <ul>
      <li><PlusLg color="#667085" size={20} /></li>
      <li><Search color="#667085" size={20} /></li>
      <li><QuestionCircle color="#667085" size={20} /></li>
    </ul>
        <div className="avatar-info mr">
        {username}<span>{userType}</span>
        </div>
        <div className="userImageBox">
      {aliasName}
      </div>
      </div>
    </>
  );
};
export default ProfileInfo;
