import React, { useEffect, useState } from "react";
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import { fetchProfile } from "../../APIs/ProfileApi";
import { useLocation, NavLink, Outlet, Routes, Route  } from "react-router-dom";
import "./header.css";
import Logo from "../../assets/images/logo.svg";
import AvatarImg from "../../assets/images/img/Avatar.png";
import ClientsIcon from "../../assets/images/icon/profile-2user.svg";
import SuppliersIcon from "../../assets/images/icon/suppliersIcon.svg";
import SalesIcon from "../../assets/images/icon/SalesIcon.svg";
import ManagementIcon from "../../assets/images/icon/ManagementIcon.svg";
import OrdersIcon from "../../assets/images/icon/OrdersIcon.svg";
import StatisticsIcon from "../../assets/images/icon/StatisticsIcon.svg";
import ExpenseIcon from "../../assets/images/icon/ExpenseIcon.svg";
import InvoicesIcon from "../../assets/images/icon/InvoicesIcon.svg";
import { Work } from "../Work/Pages/Work";
import ProfileInfo from "./ProfileInfo";
import Sales from "../Business/Pages/sales/Sales";
import Management from '../Business/Pages/management/Management'
import SelectOption from "./SelectOption";
import Profile from "./Login/Profile";


const Header = () => {
  const location = useLocation();

  const [profileData, setProfileData] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await fetchProfile();
        const parsedData = JSON.parse(data);
        setProfileData(parsedData);
      } catch (error) {
        // Handle error (show a message, log, etc.)
        console.error("Error fetching profile:", error);
      }
    };

    fetchData();
  }, []);


  const isActive = (path) => location.pathname.startsWith(path) ? "menuActive" : "";




  return (
    <>
      <div className="headerTop">
      <Container fluid>
      <Row>
        {profileData && (
          <>
          <Col className="d-flex align-items-center">
            <div className="company_logo colMinWidth">
              {profileData.organization.logo ? (
                <img src={profileData.organization.logo} alt="Company Logo" />
              ) : (
                <img src={AvatarImg} alt="DummyImg" />
              )}
              <span>{profileData.organization.name}</span>
            </div>
              <div className="SelectOptionHead">
              <SelectOption />
              </div>
            </Col>
            <Col>
            <nav className="colMinWidth">
              <div className="menu-item">
                <ul>
                  <li>
                  <NavLink to="/management" className={isActive("/management") + " managementMain"}>Business</NavLink>
                  </li>
                  <li>
                    <img src={Logo} alt="Logo" />
                  </li>
                  <li>
                    <NavLink
                      to="/work"
                      className={({ isActive }) =>
                        isActive ? "menuActive" : "link"
                        + " work"}
                    >
                      Work
                    </NavLink>
                  </li>
                </ul>
              </div>
            </nav>
            </Col>
            <Col>
            <ProfileInfo
              username={profileData.full_name}
              userType={profileData.type}
              aliasName={profileData.alias_name}
            />
           </Col>
          </>
        )}
         </Row>
    </Container>
      </div>

      <div className="headerNav">
      <Container fluid>
      <Row>
      <Col>
        <ul className="left">
          <li>
            <NavLink
             to="/clients"
             className={({ isActive }) => (isActive ? "menuActive" : "link") + " clients"}
           >
              <img src={ClientsIcon} alt="ClientsIcon" />
              Clients
            </NavLink>
          </li>
          <li>
            <NavLink
              to="/suppliers"
              className={({ isActive }) => (isActive ? "menuActive" : "link") + " suppliers"}
            >
              <img src={SuppliersIcon} alt="ClientsIcon" />
              Suppliers
            </NavLink>
          </li>
        </ul></Col>
        <Col>
        <ul className="middle">
          <li>
          <NavLink to="/sales" className={({ isActive }) => (isActive ? "menuActive" : "link") + " sales"}><img src={SalesIcon} alt="SalesIcon" />Sales</NavLink>
          </li>
          <li>
          <NavLink to="/management" className={isActive("/management") + " management"}><img src={ManagementIcon} alt="ManagementIcon" />Management</NavLink>
          </li>
         
          <li>
            <NavLink
              to="/orders "
              className={({ isActive }) => (isActive ? "menuActive" : "link") + " orders"}
            >
              <img src={OrdersIcon} alt="OrdersIcon" />
              Orders{" "}
            </NavLink>
          </li>
          <li>
            <NavLink
              to="/statistics "
              className={({ isActive }) => (isActive ? "menuActive" : "link") + " statistics"}
            >
              <img src={StatisticsIcon} alt="StatisticsIcon" />
              Statistics{" "}
            </NavLink>
          </li>
        </ul></Col>
        <Col style={{ textAlign: 'right' }}>
        <ul className="right">
          <li>
            <NavLink
              to="/expense"
              className={({ isActive }) => (isActive ? "menuActive" : "link") + " expense"}
            >
              <img src={ExpenseIcon} alt="Expense" />
              Expense
            </NavLink>
          </li>
          <li>
            <NavLink
              to="/invoices"
              className={({ isActive }) => (isActive ? "menuActive" : "link") + " invoices"}
            >
              <img src={InvoicesIcon} alt="Invoices" />
              Invoices
            </NavLink>
          </li>
        </ul></Col>
        </Row>
    </Container>
      </div>

      <div className="main-wrapper">
        <Routes>
          <Route path="/work" element={<Work />} />
          <Route path="/sales" element={<Sales />} />
          <Route path="/management" element={<Management />} />
          <Route path="/profile" element={<Profile />} />
   
        </Routes>
        <Outlet />
      </div>
    </>
  );
};

export default Header;
