import React ,{ useState } from 'react';
import ButtonGroup from 'react-bootstrap/ButtonGroup';
import ToggleButton from 'react-bootstrap/ToggleButton';
import { Envelope, Telephone, Calendar,ChevronDown } from "react-bootstrap-icons";
import dayjs from 'dayjs';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import { DatePicker } from '@mui/x-date-pickers/DatePicker';
import Button from "@mui/material/Button";
import Typography from '@mui/material/Typography';
import Form from 'react-bootstrap/Form';



function RadioButton() {
  const [radioValue, setRadioValue] = useState('1');
  const [value, setValue] = React.useState(dayjs('2022-04-17'));

 

  const radios = [
    { name: 'Email', value: '1', icon: <Envelope size={20} /> },
    { name: 'Phone', value: '2', icon: <Telephone size={20} /> },
    { name: 'Meeting', value: '3', icon: <Calendar size={20} /> },
  ];

  return (
    <div className='ContactModel'>
   <span>Contact Type</span>
      <ButtonGroup className='radioSelectButton' >
        {radios.map((radio, idx) => (
              <div className='radioSelectButtons'>
          <ToggleButton
            key={idx}
            id={`radio-${idx}`}
            type="radio"
            variant={idx % 2 ? 'outlineBox' : 'selectBox'}
            name="radio"
            value={radio.value}
            checked={radioValue === radio.value}
            onChange={(e) => setRadioValue(e.currentTarget.value)}
          >
        {radio.name} {radio.icon}
          </ToggleButton>
          </div>
        ))}
      </ButtonGroup>
      <LocalizationProvider dateAdapter={AdapterDayjs}>
      <span className="flexRemove">Date</span>
      <DatePicker className='datepickerField'
      value={value}
      onChange={(newValue) => setValue(newValue)}
      slots={{ openPickerIcon: ChevronDown }}
      size={20}
    />
    </LocalizationProvider>
    <span>Note</span>
    <Typography sx={{ p: 0 }}>  
           <Form.Control
             as="textarea"
             placeholder= "Value"
             style={{ height: '157px' }}
           />
       
       </Typography>

       <div className='popoverbottom'>
            <Button className='closebox'>
              Cancel
            </Button>
            <Button className='savebox' >
              Save
            </Button>
          </div>
    </div>
  );
}

export default RadioButton;
