import * as React from "react";
import {
  Send,
  ClockHistory,
  Tag,
  Layers,
  ThreeDots,
} from "react-bootstrap-icons";
import Menu from "@mui/material/Menu";
import MenuItem from "@mui/material/MenuItem";
import IconButton from "@mui/material/IconButton";

const ActionsDots = () => {
  const [anchorEl, setAnchorEl] = React.useState(null);
  const open = Boolean(anchorEl);
  const handleClick = (event) => {
    setAnchorEl(event.currentTarget);
  };
  const handleClose = () => {
    setAnchorEl(null);
  };

  const options = [
    { label: "Resend", icon: <Send color="#344054" size={20} /> },
    { label: "History", icon: <ClockHistory color="#344054" size={20} /> },
    { label: "Label", icon: <Tag color="#344054" size={20} /> },
    { label: "Replicate ", icon: <Layers color="#344054" size={20} /> },
  ];

  return (
    <>
      <IconButton
        aria-label="more"
        id="long-button"
        aria-controls={open ? "long-menu" : undefined}
        aria-expanded={open ? "true" : undefined}
        aria-haspopup="true"
        onClick={handleClick}
      >
        <ThreeDots size={24} color="#667085" />
      </IconButton>
      <Menu
        className="ActionsDotsBox"
        id="long-menu"
        MenuListProps={{
          "aria-labelledby": "long-button",
        }}
        anchorEl={anchorEl}
        open={open}
        onClose={handleClose}
        PaperProps={{
          style: {
            borderBottom: "1px solid #EAECF0",
            width: "215px",
          },
        }}
      >
        {options.map((option) => (
          <MenuItem key={option.label} onClick={handleClose}>
            {option.label}
            {option.icon}
          </MenuItem>
        ))}
      </Menu>
    </>
  );
};
export default ActionsDots;
